UPDATE decision_nodes SET data = '{"type":"question","module":1,"title":"Oncological Emergencies — Triage","body":"[Onc Emergency Steps Summary](#/info/onc-emergency-summary) | [Chemo Regimens & Toxicities](#/info/chemo-regimens) | [CRS / ICANS Protocol](#/info/crs-icans-protocol) | [ICI Toxicity Algorithm](#/info/ici-toxicity-algorithm)\n\n**Background:** Cancer patients account for ~5% of ED visits but disproportionate morbidity. Major oncologic emergencies share a common trait: **early recognition + rapid time-critical action prevents death or permanent disability**. [1][2]\n\n**Always ask:**\n1. What is the cancer type and stage?\n2. What chemotherapy / targeted agent / immunotherapy / CAR-T? When was last dose? (See [Chemo Regimens](#/info/chemo-regimens))\n3. Last ANC, platelets, electrolytes?\n4. Performance status (ECOG)?\n\nWhat is the chief complaint?","citation":[1,2,9,20,21],"options":[{"label":"Fever in cancer patient","description":"On chemo or recent chemo — suspect febrile neutropenia","next":"onc-fn-recognize","urgency":"critical"},{"label":"New lab abnormalities (K↑, PO4↑, Ca↓, urate↑)","description":"Lymphoma/leukemia on induction or recent — suspect TLS","next":"onc-tls-recognize","urgency":"critical"},{"label":"AMS / weakness / polyuria / nausea","description":"Breast/lung/myeloma → suspect hypercalcemia of malignancy","next":"onc-hyperca-recognize"},{"label":"Back pain ± neuro deficit","description":"Known cancer or new — suspect malignant cord compression","next":"onc-mscc-recognize","urgency":"critical"},{"label":"Facial/upper extremity swelling, dyspnea","description":"Lung cancer/lymphoma — suspect SVC syndrome","next":"onc-svc-recognize"},{"label":"Markedly elevated WBC + symptoms","description":"AML/CML — suspect leukostasis or hyperviscosity","next":"onc-leuko-recognize","urgency":"critical"},{"label":"Hypotension / dyspnea + known/suspected effusion","description":"Lung/breast/lymphoma — suspect malignant pericardial tamponade","next":"onc-pericardial-recognize","urgency":"critical"},{"label":"Recent CAR-T / bispecific + fever / hypotension / hypoxia","description":"Cytokine release syndrome (CRS) — graded by ASTCT","next":"onc-crs-recognize","urgency":"critical"},{"label":"Recent CAR-T / bispecific + confusion / seizure / aphasia","description":"ICANS (Immune Effector Cell-Associated Neurotoxicity)","next":"onc-icans-recognize","urgency":"critical"},{"label":"On checkpoint inhibitor — new organ symptom","description":"Suspect immune-related adverse event (irAE)","next":"onc-ici-recognize","urgency":"critical"}],"calculatorLinks":[{"id":"ecog-performance","label":"ECOG Performance Status"},{"id":"mascc-score","label":"MASCC Risk Index"},{"id":"tls-cairo-bishop","label":"TLS Risk (Cairo-Bishop)"},{"id":"hyperca-severity","label":"Hypercalcemia Severity"},{"id":"crs-grade","label":"CRS Grade (ASTCT)"},{"id":"ice-icans","label":"ICE / ICANS Score"},{"id":"mscc-decision","label":"MSCC Decision Aid"},{"id":"corrected-calcium","label":"Corrected Calcium"}],"summary":"Major onc emergencies: FN, TLS, hyperCa, MSCC, SVC, leukostasis, pericardial tamponade, CRS, ICANS, ICI irAEs"}'::jsonb
