-- Node: onc-tls-recognize (1 field(s) changed)
UPDATE decision_nodes SET data = '{"type":"info","module":3,"title":"Tumor Lysis Syndrome — Cairo-Bishop Criteria","body":"**Cairo-Bishop Laboratory TLS** — ≥2 of the following within 3 days before to 7 days after cytotoxic therapy: [6][7]\n\n| Lab | Criterion |\n|-----|-----------|\n| Uric acid | ≥8 mg/dL or 25% increase |\n| Potassium | ≥6 mEq/L or 25% increase |\n| Phosphate | ≥4.5 mg/dL (adult) or 25% increase |\n| Calcium | ≤7 mg/dL or 25% decrease |\n\n**Clinical TLS** = Lab TLS + at least one of:\n* Creatinine ≥1.5× ULN\n* Cardiac dysrhythmia / sudden death\n* Seizure\n\n**Highest risk:**\n* Burkitt lymphoma\n* T-cell ALL with high WBC\n* Bulky non-Hodgkin lymphoma\n* AML with high WBC\n* CLL with bulky disease starting venetoclax\n* Hepatocellular carcinoma with TACE\n* Spontaneous TLS (rare, in highly proliferative tumors)\n\n**Key risk factors:** baseline elevated uric acid, baseline renal dysfunction, dehydration, oliguria.","citation":[6,7],"next":"onc-tls-treat","calculatorLinks":[{"id":"tls-cairo-bishop","label":"TLS Risk (Cairo-Bishop)"}],"summary":"Cairo-Bishop: ≥2 lab abnormalities (urate↑, K↑, PO4↑, Ca↓); clinical TLS = lab + Cr/arrhythmia/seizure"}'::jsonb
WHERE id = 'onc-tls-recognize' AND tree_id = 'oncological-emergencies';

-- Node: onc-tls-treat (1 field(s) changed)
UPDATE decision_nodes SET data = '{"type":"info","module":3,"title":"TLS Management — Aggressive IVF + Hypouricemic Agent","body":"**Step 1 — Aggressive IV Hydration (cornerstone):** [6][7]\n* **Normal saline 2-3 L/m²/day** (200-250 mL/hr in adults if no CHF)\n* Goal urine output: **>100 mL/hr** (maintain even if oliguric — push fluids unless overload)\n* AVOID potassium-containing fluids (no LR)\n* AVOID alkalinization (urine alkalinization no longer recommended — promotes calcium phosphate precipitation)\n\n**Step 2 — Hypouricemic Therapy:** [6][8]\n\n**[Allopurinol](#/drug/allopurinol/tls)** for low-intermediate risk:\n* 300 mg PO daily, start 2-3 days before chemo\n* Blocks xanthine oxidase → prevents NEW urate formation\n* Does NOT lower existing urate\n\n**[Rasburicase](#/drug/rasburicase/tls)** for high-risk or established TLS:\n* 0.2 mg/kg IV × 1 (single dose effective in most cases)\n* Recombinant urate oxidase — converts urate to allantoin\n* Drops urate within hours\n* **CHECK G6PD if time allows** — contraindicated in G6PD deficiency (causes hemolysis)\n* CONTRAINDICATED in pregnancy, breastfeeding\n* **Sample handling:** post-rasburicase uric acid samples must be on ice — false low otherwise\n\n**Step 3 — Manage Electrolyte Derangements:**\n* **Hyperkalemia:** see [Hyperkalemia consult] — calcium gluconate, insulin/D50, kayexalate, dialysis\n* **Hyperphosphatemia:** [sevelamer](#/drug/sevelamer/hyperphosphatemia) 800-1600 mg PO TID with meals; aluminum hydroxide acutely\n* **Hypocalcemia:** treat ONLY if symptomatic (Ca + PO4 product >60 → precipitation risk); calcium gluconate 1-2g IV slow\n* **Hyperuricemia:** rasburicase as above\n\n**Step 4 — Renal Replacement Therapy if:**\n* K >6.5 refractory to medical therapy\n* PO4 >10 or rapidly rising\n* Symptomatic hypocalcemia from PO4 binding\n* Volume overload preventing adequate hydration\n* Uremia symptoms\n* Acidosis refractory\n\n**Disposition:** ICU for clinical TLS or high-risk lab TLS; telemetry minimum for any lab TLS.","citation":[6,7,8],"next":"onc-tls-disposition","calculatorLinks":[{"id":"tls-cairo-bishop","label":"TLS Risk (Cairo-Bishop)"},{"id":"corrected-calcium","label":"Corrected Calcium"}],"summary":"TLS: NS 2-3 L/m²/d (UOP >100 mL/hr) + rasburicase if urate >8 (check G6PD!); no alkalinization; HD for refractory K/PO4"}'::jsonb
WHERE id = 'onc-tls-treat' AND tree_id = 'oncological-emergencies';

-- Node: onc-hyperca-treat (1 field(s) changed)
UPDATE decision_nodes SET data = '{"type":"info","module":4,"title":"HCM Treatment — IVF + Calcitonin + Bisphosphonate","body":"**Step 1 — Aggressive IV Hydration (cornerstone):** [9][10]\n* **Normal saline 200-300 mL/hr** until euvolemic, then 100-150 mL/hr\n* Goal urine output >100 mL/hr\n* Most patients are profoundly volume depleted from hypercalcemia-induced nephrogenic DI\n* Avoid LR (contains calcium)\n* AVOID loop diuretics in routine cases — only use if volume overload develops; prior dogma of forced calciuresis with furosemide is not supported by evidence and can worsen depletion [10]\n\n**Step 2 — Calcitonin (rapid onset, short duration):**\n* **[Calcitonin](#/drug/calcitonin/hypercalcemia)** 4 IU/kg SC or IM q12h\n* Drops Ca by 1-2 mg/dL within 4-6 hours\n* Tachyphylaxis develops within 48-72 hours\n* Bridge while bisphosphonate takes effect\n\n**Step 3 — Bisphosphonate (sustained effect):**\n* **[Zoledronic acid](#/drug/zoledronic-acid/hypercalcemia)** 4 mg IV over 15-30 minutes — preferred over pamidronate (more potent, faster)\n* Onset 24-48 hours; peak effect 4-7 days; duration 4 weeks\n* Adjust dose for renal function (avoid if CrCl <30)\n* Risks: osteonecrosis of jaw (long-term), atypical femur fracture, acute kidney injury\n\n**Step 4 — Denosumab (if renal failure or bisphosphonate-refractory):**\n* **[Denosumab](#/drug/denosumab/hypercalcemia)** 120 mg SC\n* RANKL inhibitor — does not require renal clearance\n* Use when CrCl <30 or refractory after 7 days of bisphosphonate\n* Risk: severe hypocalcemia (monitor)\n\n**Step 5 — Steroids (if vit-D mediated):**\n* Lymphoma, myeloma, granulomatous disease\n* [Prednisone](#/drug/prednisone/hypercalcemia) 40-60 mg PO daily\n\n**Step 6 — Hemodialysis if:**\n* Ca >18 with neuro/cardiac sx\n* Renal failure preventing IVF\n* Refractory to medical therapy","citation":[9,10],"next":"onc-hyperca-disposition","calculatorLinks":[{"id":"corrected-calcium","label":"Corrected Calcium"},{"id":"hyperca-severity","label":"Hypercalcemia Severity"}],"summary":"HCM: NS 200-300 mL/hr + calcitonin 4 IU/kg q12h (rapid bridge) + zoledronic acid 4 mg IV (sustained); avoid loop diuretics"}'::jsonb
WHERE id = 'onc-hyperca-treat' AND tree_id = 'oncological-emergencies';

-- Node: onc-mscc-treat (1 field(s) changed)
UPDATE decision_nodes SET data = '{"type":"info","module":5,"title":"MSCC — Steroids First, Then Image","body":"**Step 1 — Dexamethasone IMMEDIATELY (do not wait for imaging):** [11][13]\n* **[Dexamethasone](#/drug/dexamethasone/mscc)** 10 mg IV bolus, then 4 mg IV/PO q6h\n* Some protocols use higher loading dose (96 mg) for severe deficit — efficacy similar, more side effects\n* Reduces vasogenic edema → preserves neurologic function\n* Start before imaging if high suspicion — every minute of cord compression risks permanent deficit\n\n**Step 2 — Emergent MRI of WHOLE Spine:** [11][12]\n* MRI with gadolinium\n* **Image entire spine** — multi-level disease in 30%, missing co-lesions affects radiation planning\n* If MRI unavailable: CT myelogram\n* CT alone insufficient\n\n**Step 3 — Multi-disciplinary Consults (call from ED):**\n* **Neurosurgery** (spine surgery) — for surgical decompression candidates\n* **Radiation Oncology** — for emergent radiation\n* **Medical Oncology** — for tumor type, primary tx options\n\n**Step 4 — Definitive Treatment Selection:**\n\n**Surgery + Radiation (Patchell 2005 trial standard):** [13]\n* For ambulatory or recently non-ambulatory (<48h) patients with ≥3 month life expectancy\n* Single-level compression\n* Stable spine\n* Demonstrated to preserve ambulation in RCT (84% vs 57% with RT alone)\n\n**Radiation alone:**\n* Patients not surgical candidates\n* Multi-level disease\n* Radiosensitive tumors (lymphoma, myeloma, small cell lung, germ cell)\n* Life expectancy <3 months\n\n**Chemotherapy:**\n* Highly chemo-sensitive tumors (germ cell, lymphoma, SCLC)\n* Adjunct to RT/surgery\n\n**Step 5 — Supportive:**\n* Foley catheter if retention\n* Bowel regimen\n* DVT prophylaxis (mechanical only if surgery imminent; chemical otherwise)\n* Pain control: opioids, gabapentin for neuropathic component","citation":[11,12,13],"next":"onc-mscc-disposition","calculatorLinks":[{"id":"mscc-decision","label":"MSCC Decision Aid"},{"id":"ecog-performance","label":"ECOG Performance Status"}],"summary":"MSCC: dex 10 mg IV STAT (before imaging) → MRI whole spine → neurosurg + rad onc consult; surgery + RT > RT alone if ambulatory"}'::jsonb
WHERE id = 'onc-mscc-treat' AND tree_id = 'oncological-emergencies';

