-- Node: onc-chemo-reference (1 field(s) changed)
UPDATE decision_nodes SET data = '{"type":"info","module":12,"title":"Chemotherapy Reference — Nadirs & Toxicities","body":"[Comprehensive Chemotherapy Regimens & Side Effects](#/info/chemo-regimens)\n\n**ED-Critical Toxicity Patterns:**\n\n**Cardiotoxicity:**\n* Anthracyclines (doxorubicin, daunorubicin) — cumulative dose-dependent CHF\n* Trastuzumab — reversible LV dysfunction\n* 5-FU, capecitabine — coronary vasospasm\n* Immune checkpoint inhibitors — myocarditis (rare but lethal)\n\n**Pulmonary:**\n* Bleomycin — pulmonary fibrosis (avoid high FiO2)\n* Methotrexate — pneumonitis\n* Checkpoint inhibitors — pneumonitis (steroids)\n\n**Nephrotoxicity:**\n* Cisplatin — tubular injury\n* Methotrexate — crystalluria (alkalinize, leucovorin rescue)\n* Ifosfamide — Fanconi syndrome\n\n**Neurotoxicity:**\n* Vincristine — peripheral neuropathy, never IT (fatal)\n* Oxaliplatin — cold-triggered dysesthesia\n* Ifosfamide — encephalopathy (methylene blue rescue)\n* Cisplatin — ototoxicity\n\n**Hematologic Nadirs:**\n* Most cytotoxics: nadir day 7-14, recovery day 21-28\n* Carboplatin/cisplatin: nadir day 14-21\n* Mitomycin: delayed nadir day 28-42\n* Always check date of last cycle and nadir expectation\n\n**Immune-Related Adverse Events (ICI):**\n* Can occur weeks to months after dose\n* Colitis (steroids + infliximab if refractory)\n* Hepatitis\n* Endocrinopathies (thyroiditis, hypophysitis, adrenalitis)\n* Pneumonitis\n* Myocarditis\n\n**Extravasation Emergencies:**\n* Anthracyclines, vinca alkaloids → severe tissue necrosis\n* Stop infusion, aspirate, do NOT flush\n* Anthracycline: dexrazoxane antidote within 6h\n* Vinca: hyaluronidase + warm compress\n* Mitomycin: cold compress + DMSO","citation":[18,19],"next":"onc-disposition-summary","summary":"Chemo toxicities: cardiotox (anthracyclines), pulm (bleo), neuro (vinca), nadir d7-14; ICI = irAEs weeks-months later"}'::jsonb
WHERE id = 'onc-chemo-reference' AND tree_id = 'oncological-emergencies';

